import type { ComponentProps, ComponentRef } from 'react';
import {
  Checkbox as CheckboxPrimitive,
  useCheckbox,
  useCheckboxContext,
  useCheckboxGroup,
  useCheckboxGroupContext,
} from '@ark-ui/react/checkbox';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { CheckIcon, IndeterminateIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Checkbox.module.css';

type CheckboxSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type CheckboxRootProps = ComponentProps<typeof CheckboxPrimitive.Root> & { size?: CheckboxSize };

const CheckboxRoot = forwardRef<ComponentRef<typeof CheckboxPrimitive.Root>, CheckboxRootProps>(
  function CheckboxRoot({ className, size = 'md', ...props }, ref) {
    return (
      <CheckboxPrimitive.Root
        ref={ref}
        data-slot="checkbox-root"
        data-size={size}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const CheckboxRootProvider = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.RootProvider>,
  ComponentProps<typeof CheckboxPrimitive.RootProvider> & { size?: CheckboxSize }
>(function CheckboxRootProvider({ className, size = 'md', ...props }, ref) {
  return (
    <CheckboxPrimitive.RootProvider
      ref={ref}
      data-slot="checkbox-root-provider"
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const CheckboxControl = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.Control>,
  ComponentProps<typeof CheckboxPrimitive.Control>
>(function CheckboxControl({ className, ...props }, ref) {
  return (
    <CheckboxPrimitive.Control
      ref={ref}
      data-slot="checkbox-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const CheckboxIndicator = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.Indicator>,
  ComponentProps<typeof CheckboxPrimitive.Indicator>
>(function CheckboxIndicator({ className, children, indeterminate, ...props }, ref) {
  const slot = indeterminate
    ? 'checkbox-indicator-indeterminate-icon'
    : 'checkbox-indicator-checked-icon';

  return (
    <CheckboxPrimitive.Indicator
      ref={ref}
      data-slot="checkbox-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      indeterminate={indeterminate}
      {...props}
    >
      {children ?? (
        <span aria-hidden="true" data-slot={slot} className={styles.icon}>
          {indeterminate ? <IndeterminateIcon /> : <CheckIcon />}
        </span>
      )}
    </CheckboxPrimitive.Indicator>
  );
});

const CheckboxHiddenInput = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.HiddenInput>,
  ComponentProps<typeof CheckboxPrimitive.HiddenInput>
>(function CheckboxHiddenInput(props, ref) {
  return <CheckboxPrimitive.HiddenInput ref={ref} data-slot="checkbox-hidden-input" {...props} />;
});

const CheckboxLabel = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.Label>,
  ComponentProps<typeof CheckboxPrimitive.Label>
>(function CheckboxLabel({ className, ...props }, ref) {
  return (
    <CheckboxPrimitive.Label
      ref={ref}
      data-slot="checkbox-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const CheckboxGroup = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.Group>,
  ComponentProps<typeof CheckboxPrimitive.Group>
>(function CheckboxGroup({ className, ...props }, ref) {
  return (
    <CheckboxPrimitive.Group
      ref={ref}
      data-slot="checkbox-group"
      className={clsx(styles.group, normalizeClassName(className))}
      {...props}
    />
  );
});

const CheckboxGroupProvider = forwardRef<
  ComponentRef<typeof CheckboxPrimitive.GroupProvider>,
  ComponentProps<typeof CheckboxPrimitive.GroupProvider>
>(function CheckboxGroupProvider({ className, ...props }, ref) {
  return (
    <CheckboxPrimitive.GroupProvider
      ref={ref}
      data-slot="checkbox-group-provider"
      className={clsx(styles.group, normalizeClassName(className))}
      {...props}
    />
  );
});

const CheckboxContext = CheckboxPrimitive.Context;

const Checkbox = Object.assign(CheckboxRoot, {
  Root: CheckboxRoot,
  RootProvider: CheckboxRootProvider,
  Control: CheckboxControl,
  Indicator: CheckboxIndicator,
  HiddenInput: CheckboxHiddenInput,
  Label: CheckboxLabel,
  Group: CheckboxGroup,
  GroupProvider: CheckboxGroupProvider,
  Context: CheckboxContext,
});

export { Checkbox, useCheckbox, useCheckboxContext, useCheckboxGroup, useCheckboxGroupContext };
export type {
  CheckboxCheckedChangeDetails,
  CheckboxCheckedState,
  CheckboxContextProps,
  CheckboxGroupProviderBaseProps,
  CheckboxGroupProviderProps,
  CheckboxGroupProps,
  CheckboxRootProviderBaseProps,
  CheckboxRootProviderProps,
  UseCheckboxContext,
  UseCheckboxGroupContext,
  UseCheckboxGroupProps,
  UseCheckboxGroupReturn,
  UseCheckboxProps,
  UseCheckboxReturn,
} from '@ark-ui/react/checkbox';
export type { CheckboxRootProps, CheckboxSize };

@layer ui.components {
  .root {
    display: inline-flex;
    align-items: center;
    gap: var(--checkbox-gap, var(--spacing-2));
    vertical-align: middle;
    color: var(--checkbox-label-color, var(--color-foreground));
    cursor: pointer;

    &[data-disabled],
    &[data-readonly] {
      cursor: default;
    }
  }

  .control {
    box-sizing: border-box;
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    width: var(--_checkbox-size, 1.25rem);
    height: var(--_checkbox-size, 1.25rem);
    margin: 0;
    border: var(--checkbox-border-width, var(--border-width-sm)) solid
      var(--checkbox-border-color, var(--color-border));
    border-radius: var(--checkbox-radius, var(--radius-xs));
    padding: 0;
    background-color: var(--checkbox-bg, var(--color-background));
    color: var(--checkbox-color, var(--color-primary-foreground));
    line-height: 0;
    user-select: none;
    transition:
      background-color var(--checkbox-transition, var(--transition-default)),
      border-color var(--checkbox-transition, var(--transition-default)),
      color var(--checkbox-transition, var(--transition-default)),
      opacity var(--checkbox-transition, var(--transition-default));

    &[data-state='checked'],
    &[data-state='indeterminate'] {
      border-color: var(--checkbox-border-color-checked, var(--color-primary));
      background-color: var(--checkbox-bg-checked, var(--color-primary));
    }

    &[data-focus-visible] {
      outline: var(--checkbox-focus-ring-width, var(--border-width-sm)) solid
        var(--checkbox-focus-ring-color, var(--color-ring));
      outline-offset: var(--checkbox-focus-ring-offset, var(--border-width-sm));
    }

    &[data-invalid] {
      border-color: var(--checkbox-border-color-invalid, var(--color-destructive));
      color: var(--checkbox-color-invalid, var(--color-primary-foreground));

      &[data-state='checked'],
      &[data-state='indeterminate'] {
        border-color: var(--checkbox-border-color-invalid, var(--color-destructive));
        background-color: var(--checkbox-bg-invalid, var(--color-destructive));
      }

      &[data-focus-visible] {
        outline-color: var(--checkbox-border-color-invalid, var(--color-destructive));
      }
    }

    @media (hover: hover) {
      &[data-state='unchecked']:not([data-readonly]):hover {
        background-color: var(--checkbox-bg-hover, var(--color-accent));
      }
    }

    &[data-disabled] {
      opacity: var(--checkbox-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
  }

  .root[data-size='xs'] .control {
    --_checkbox-size: var(--checkbox-size-xs, 0.875rem);
    --_checkbox-icon-size: var(--checkbox-icon-size-xs, 0.5rem);
  }

  .root[data-size='sm'] .control {
    --_checkbox-size: var(--checkbox-size-sm, 1rem);
    --_checkbox-icon-size: var(--checkbox-icon-size-sm, 0.625rem);
  }

  .root[data-size='md'] .control {
    --_checkbox-size: var(--checkbox-size-md, 1.25rem);
    --_checkbox-icon-size: var(--checkbox-icon-size-md, 0.75rem);
  }

  .root[data-size='lg'] .control {
    --_checkbox-size: var(--checkbox-size-lg, 1.5rem);
    --_checkbox-icon-size: var(--checkbox-icon-size-lg, 0.875rem);
  }

  .root[data-size='xl'] .control {
    --_checkbox-size: var(--checkbox-size-xl, 1.75rem);
    --_checkbox-icon-size: var(--checkbox-icon-size-xl, 1rem);
  }

  .indicator {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;
    color: inherit;
  }

  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--_checkbox-icon-size, 0.75rem);
    height: var(--_checkbox-icon-size, 0.75rem);
    color: inherit;
    line-height: 0;

    & > svg {
      width: 100%;
      height: 100%;
    }
  }

  .label {
    color: var(--checkbox-label-color, var(--color-foreground));
    font-size: var(--checkbox-label-font-size, var(--text-sm));
    font-weight: var(--checkbox-label-font-weight, var(--weight-medium));
    line-height: var(--checkbox-label-line-height, var(--line-height-text-sm));
  }

  .group {
    display: flex;
    flex-direction: column;
    gap: var(--checkbox-group-gap, var(--spacing-2));
    color: var(--checkbox-group-color, var(--color-foreground));
  }
}
